    }
  }

  void _handleProfileRoute(Uri uri, BuildContext context) {
    if (uri.pathSegments.length < 2) {
      debugPrint('Missing profile ID');
      return;
    }

    final profileId = uri.pathSegments[1];
    
    // Validate profile ID format (simple numeric check)
    if (!RegExp(r'^\d+$').hasMatch(profileId)) {
      debugPrint('Invalid profile ID format: $profileId');
      return;
    }

    // Navigate to profile screen
    Navigator.pushNamed(context, '/profile', arguments: {'id': profileId});
  }

  void _handlePaymentRoute(Uri uri, BuildContext context) {
    if (uri.pathSegments.length < 2) {
      debugPrint('Missing payment action');
      return;
    }

    final action = uri.pathSegments[1];
    
    // Validate action
    if (!_allowedPaymentActions.contains(action)) {
      debugPrint('Invalid payment action: $action');
      return;
    }

    // Parse additional parameters
    final Map<String, String> params = {};
    for (var entry in uri.queryParameters.entries) {
